from hypothesis import given, settings
from hypothesis import strategies as st

from roster_quo_hash_apostrophe import format_record, parse_record

ALPHABET = "ab01#'"


def test_empty_field_round_trips():
    fields = ["", "early", ""]
    assert parse_record(format_record(fields)) == fields


def test_quote_only_field_round_trips():
    fields = ["''", "late"]
    assert parse_record(format_record(fields)) == fields


def test_adjacent_specials_round_trip():
    fields = ["#'#", "night"]
    assert parse_record(format_record(fields)) == fields


@settings(derandomize=True, database=None, max_examples=50)
@given(st.lists(st.text(alphabet=ALPHABET, max_size=6), min_size=1, max_size=5))
def test_round_trip_property(fields):
    assert parse_record(format_record(fields)) == fields

